/**
 * Stdio JSON-line IPC discriminated unions shared between the
 * supervisor (in the Fastify process) and the sidecar entry point.
 *
 * Binary payloads (output / input) ride as base64-encoded strings so the
 * envelope stays parseable as JSON per ADR-001.
 */

export type SupervisorToSidecar =
  | { kind: "attach"; chatId: string; cols: number; rows: number; cwd?: string }
  | { kind: "detach"; chatId: string }
  | { kind: "input"; chatId: string; base64: string }
  | { kind: "resize"; chatId: string; cols: number; rows: number }
  | { kind: "pause"; chatId: string }
  | { kind: "resume"; chatId: string }
  | { kind: "dispose"; chatId: string }
  | { kind: "shutdown" };

export type SidecarToSupervisor =
  | { kind: "ready" }
  | { kind: "snapshot"; chatId: string; text: string }
  | { kind: "live"; chatId: string }
  | { kind: "output"; chatId: string; base64: string }
  | { kind: "exit"; chatId: string; code: number | null; signal: string | null }
  | { kind: "error"; chatId: string | null; message: string };

/**
 * Spawns the pty-sidecar Node child and routes IPC frames between it
 * and the bound WebSocket(s) per chatId. Maintains a per-chat
 * Set<WebSocket> so v2 multi-viewer is a no-op extension (ADR-006).
 *
 * On unexpected sidecar exit, the supervisor encodes one ERROR frame
 * and broadcasts to every bound WS, then closes them. The Fastify
 * process keeps serving non-PTY routes — no auto-restart (ADR-007).
 */
import * as childProcess from "node:child_process";
import * as readline from "node:readline";
import * as path from "node:path";
import { fileURLToPath } from "node:url";
import type {
  SidecarToSupervisor,
  SupervisorToSidecar,
} from "./sidecar-ipc-types.ts";
import {
  encodeError,
  encodeExit,
  encodeLive,
  encodeOutput,
  encodeSnapshot,
} from "../../../web/src/lib/pty-ws-protocol.ts";

interface SidecarWebSocket {
  send(data: Uint8Array): void;
  close(): void;
}

export interface SidecarSupervisor {
  start(): Promise<void>;
  bindWebSocket(chatId: string, socket: SidecarWebSocket): void;
  unbindWebSocket(chatId: string, socket: SidecarWebSocket): void;
  disposeChat(chatId: string): void;
  /**
   * Forward a client-originated WS message (binary frame) to the
   * sidecar. The route handler decodes the wire tag and delegates the
   * payload here.
   */
  sendInput(chatId: string, bytes: Uint8Array): void;
  sendResize(chatId: string, cols: number, rows: number): void;
  sendPause(chatId: string): void;
  sendResume(chatId: string): void;
  attach(chatId: string, cols: number, rows: number, cwd?: string): void;
  detach(chatId: string): void;
  hasSession(chatId: string): boolean;
  shutdown(): Promise<void>;
  isDead(): boolean;
}

export interface CreateSidecarSupervisorOptions {
  sidecarEntry?: string;
  spawn?: typeof childProcess.spawn;
}

function defaultSidecarEntry(): string {
  const here = path.dirname(fileURLToPath(import.meta.url));
  return path.join(here, "pty-sidecar.ts");
}

export function createSidecarSupervisor(
  opts: CreateSidecarSupervisorOptions = {},
): SidecarSupervisor {
  const sidecarEntry = opts.sidecarEntry ?? defaultSidecarEntry();
  const spawn = opts.spawn ?? childProcess.spawn;

  let child: childProcess.ChildProcessByStdio<
    NodeJS.WritableStream,
    NodeJS.ReadableStream,
    null
  > | null = null;
  let dead = false;
  const bindings = new Map<string, Set<SidecarWebSocket>>();
  const liveChats = new Set<string>();

  const sendIpc = (message: SupervisorToSidecar): void => {
    if (!child || dead) return;
    child.stdin.write(JSON.stringify(message) + "\n");
  };

  const broadcastError = (chatId: string | null, messageText: string): void => {
    const frame = encodeError(messageText);
    if (chatId === null) {
      for (const set of bindings.values()) {
        for (const socket of set) {
          try {
            socket.send(frame);
          } catch {}
        }
      }
      return;
    }
    const set = bindings.get(chatId);
    if (!set) return;
    for (const socket of set) {
      try {
        socket.send(frame);
      } catch {}
    }
  };

  const dispatchIpc = (line: string): void => {
    let message: SidecarToSupervisor;
    try {
      message = JSON.parse(line);
    } catch {
      return;
    }
    if (message.kind === "ready") return;
    if (message.kind === "error") {
      broadcastError(message.chatId, message.message);
      return;
    }
    const set = bindings.get(message.chatId);
    if (!set) return;
    if (message.kind === "output") {
      const frame = encodeOutput(new Uint8Array(Buffer.from(message.base64, "base64")));
      for (const socket of set) {
        try {
          socket.send(frame);
        } catch {}
      }
    } else if (message.kind === "snapshot") {
      const frame = encodeSnapshot(message.text);
      for (const socket of set) {
        try {
          socket.send(frame);
        } catch {}
      }
    } else if (message.kind === "live") {
      const frame = encodeLive();
      for (const socket of set) {
        try {
          socket.send(frame);
        } catch {}
      }
    } else if (message.kind === "exit") {
      const frame = encodeExit({ code: message.code, signal: message.signal });
      for (const socket of set) {
        try {
          socket.send(frame);
        } catch {}
      }
    }
  };

  return {
    isDead() {
      return dead;
    },
    hasSession(chatId) {
      return liveChats.has(chatId);
    },
    async start() {
      const spawnCommand = process.execPath;
      const tsxLoader = path.resolve(
        path.dirname(fileURLToPath(import.meta.url)),
        "../../../../node_modules/tsx/dist/loader.mjs",
      );
      const spawnArgs = [
        "--no-warnings",
        "--import",
        "tsx",
        sidecarEntry,
      ];
      void tsxLoader;
      child = spawn(spawnCommand, spawnArgs, {
        stdio: ["pipe", "pipe", "inherit"],
        env: { ...process.env },
      }) as childProcess.ChildProcessByStdio<
        NodeJS.WritableStream,
        NodeJS.ReadableStream,
        null
      >;
      const rl = readline.createInterface({ input: child.stdout });
      const ready = new Promise<void>((resolve, reject) => {
        const onLine = (line: string) => {
          try {
            const parsed = JSON.parse(line);
            if (parsed?.kind === "ready") {
              resolve();
              return;
            }
          } catch {}
        };
        rl.once("line", onLine);
        child!.once("exit", () => {
          reject(new Error("sidecar exited before ready"));
        });
      });
      rl.on("line", dispatchIpc);
      child.on("exit", () => {
        dead = true;
        const message = "PTY sidecar exited; reload to recover";
        broadcastError(null, message);
        for (const set of bindings.values()) {
          for (const socket of set) {
            try {
              socket.close();
            } catch {}
          }
        }
        bindings.clear();
        liveChats.clear();
      });
      await ready;
    },
    bindWebSocket(chatId, socket) {
      let set = bindings.get(chatId);
      if (!set) {
        set = new Set();
        bindings.set(chatId, set);
      }
      set.add(socket);
    },
    unbindWebSocket(chatId, socket) {
      const set = bindings.get(chatId);
      if (!set) return;
      set.delete(socket);
      if (set.size === 0) {
        bindings.delete(chatId);
        sendIpc({ kind: "detach", chatId });
      }
    },
    disposeChat(chatId) {
      sendIpc({ kind: "dispose", chatId });
      liveChats.delete(chatId);
      bindings.delete(chatId);
    },
    sendInput(chatId, bytes) {
      sendIpc({ kind: "input", chatId, base64: Buffer.from(bytes).toString("base64") });
    },
    sendResize(chatId, cols, rows) {
      sendIpc({ kind: "resize", chatId, cols, rows });
    },
    sendPause(chatId) {
      sendIpc({ kind: "pause", chatId });
    },
    sendResume(chatId) {
      sendIpc({ kind: "resume", chatId });
    },
    attach(chatId, cols, rows, cwd) {
      liveChats.add(chatId);
      sendIpc({ kind: "attach", chatId, cols, rows, cwd });
    },
    detach(chatId) {
      sendIpc({ kind: "detach", chatId });
    },
    async shutdown() {
      if (!child || dead) return;
      sendIpc({ kind: "shutdown" });
      await new Promise<void>((resolve) => {
        if (!child || dead) {
          resolve();
          return;
        }
        const timer = setTimeout(() => {
          try {
            child?.kill("SIGTERM");
          } catch {}
          resolve();
        }, 1000);
        child.once("exit", () => {
          clearTimeout(timer);
          resolve();
        });
      });
    },
  };
}

