import * as readline from "node:readline";
import { createChatPtyBridge, type ChatPtyBridge } from "./chat-pty-bridge.ts";
import type {
  SupervisorToSidecar,
  SidecarToSupervisor,
} from "./sidecar-ipc-types.ts";

function write(message: SidecarToSupervisor): void {
  process.stdout.write(JSON.stringify(message) + "\n");
}

function attachListeners(chatId: string, bridge: ChatPtyBridge): void {
  bridge.on((event) => {
    if (event.kind === "output") {
      write({
        kind: "output",
        chatId,
        base64: Buffer.from(event.bytes).toString("base64"),
      });
    } else if (event.kind === "exit") {
      write({ kind: "exit", chatId, code: event.code, signal: event.signal });
    } else if (event.kind === "error") {
      write({ kind: "error", chatId, message: event.message });
    }
  });
}

export function runSidecar(): void {
  const bridges = new Map<string, ChatPtyBridge>();

  const dispatch = (line: string): void => {
    let message: SupervisorToSidecar;
    try {
      message = JSON.parse(line);
    } catch (err) {
      write({ kind: "error", chatId: null, message: `bad json: ${(err as Error).message}` });
      return;
    }
    try {
      if (message.kind === "attach") {
        let bridge = bridges.get(message.chatId);
        if (!bridge) {
          bridge = createChatPtyBridge({ chatId: message.chatId, cwd: message.cwd });
          bridges.set(message.chatId, bridge);
          attachListeners(message.chatId, bridge);
        }
        const result = bridge.attach(message.cols, message.rows);
        if (result.snapshot !== null) {
          write({ kind: "snapshot", chatId: message.chatId, text: result.snapshot });
        }
        write({ kind: "live", chatId: message.chatId });
        return;
      }
      const bridge = bridges.get(message.kind === "shutdown" ? "" : message.chatId);
      if (message.kind === "shutdown") {
        for (const [, b] of bridges) {
          try {
            b.dispose();
          } catch {}
        }
        bridges.clear();
        process.exit(0);
      }
      if (!bridge) {
        write({ kind: "error", chatId: message.chatId, message: "no bridge for chat" });
        return;
      }
      switch (message.kind) {
        case "detach":
          bridge.detach();
          break;
        case "input":
          bridge.writeInput(new Uint8Array(Buffer.from(message.base64, "base64")));
          break;
        case "resize":
          bridge.resize(message.cols, message.rows);
          break;
        case "pause":
          bridge.pause();
          break;
        case "resume":
          bridge.resume();
          break;
        case "dispose":
          bridge.dispose();
          bridges.delete(message.chatId);
          break;
      }
    } catch (err) {
      const chatId = (message as { chatId?: string }).chatId ?? null;
      write({ kind: "error", chatId, message: (err as Error).message });
    }
  };

  const rl = readline.createInterface({ input: process.stdin });
  rl.on("line", dispatch);
  rl.on("close", () => process.exit(0));
  process.stdin.on("end", () => process.exit(0));

  write({ kind: "ready" });
}

const isEntrypoint = process.argv[1]?.endsWith("pty-sidecar.ts") || process.argv[1]?.endsWith("pty-sidecar.js");
if (isEntrypoint) {
  runSidecar();
}
